package download

import (
	"context"
	"os"
	"path/filepath"
	"strings"

	"github.com/cloudwego/hertz/pkg/app"
	"github.com/cloudwego/hertz/pkg/protocol/consts"
	"github.com/zy84338719/upftp/pkg/conf"
	"github.com/zy84338719/upftp/pkg/logger"
)

// Download .
// @router /download/*filepath [GET]
func Download(ctx context.Context, c *app.RequestContext) {
	// 获取文件路径
	filePath := c.Param("filepath")
	if filePath == "" {
		c.String(consts.StatusBadRequest, "File path is required")
		return
	}

	// 清理路径，防止目录遍历攻击
	filePath = strings.TrimPrefix(filePath, "/")
	filePath = strings.TrimPrefix(filePath, "./")
	filePath = strings.TrimPrefix(filePath, "../")

	// 构建完整路径
	rootPath := conf.AppConfig.Root
	if rootPath == "" {
		rootPath = "."
	}

	fullPath := filepath.Join(rootPath, filePath)

	// 检查文件是否存在
	info, err := os.Stat(fullPath)
	if err != nil {
		if os.IsNotExist(err) {
			logger.Error("File not found: %s", fullPath)
			c.String(consts.StatusNotFound, "File not found")
			return
		}
		logger.Error("Failed to stat file: %v", err)
		c.String(consts.StatusInternalServerError, "Internal server error")
		return
	}

	// 如果是目录，返回 zip 下载
	if info.IsDir() {
		// TODO: 实现目录打包下载
		c.String(consts.StatusNotImplemented, "Directory download not implemented yet")
		return
	}

	// 读取文件内容
	data, err := os.ReadFile(fullPath)
	if err != nil {
		logger.Error("Failed to read file: %v", err)
		c.String(consts.StatusInternalServerError, "Failed to read file")
		return
	}

	// 设置 Content-Type
	contentType := getContentType(fullPath)
	c.Header("Content-Type", contentType)
	c.Header("Content-Disposition", "attachment; filename=\""+filepath.Base(filePath)+"\"")
	c.SetStatusCode(consts.StatusOK)
	c.Response.BodyWriter().Write(data)
}

// getContentType 根据文件扩展名返回 Content-Type
func getContentType(filePath string) string {
	ext := strings.ToLower(filepath.Ext(filePath))
	switch ext {
	case ".html", ".htm":
		return "text/html"
	case ".css":
		return "text/css"
	case ".js":
		return "application/javascript"
	case ".json":
		return "application/json"
	case ".png":
		return "image/png"
	case ".jpg", ".jpeg":
		return "image/jpeg"
	case ".gif":
		return "image/gif"
	case ".svg":
		return "image/svg+xml"
	case ".ico":
		return "image/x-icon"
	case ".pdf":
		return "application/pdf"
	case ".txt":
		return "text/plain"
	case ".md":
		return "text/markdown"
	case ".xml":
		return "application/xml"
	case ".zip":
		return "application/zip"
	case ".mp4":
		return "video/mp4"
	case ".mp3":
		return "audio/mpeg"
	case ".webm":
		return "video/webm"
	case ".wav":
		return "audio/wav"
	default:
		return "application/octet-stream"
	}
}
